  ('aboriginal-c5fb3965-moex-00288', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '甲涉及內線交易犯罪經判決有罪確定，甲何時方得申請改名？', '["自裁判確定之日起，至執行完畢滿6月後，方得申請", "自裁判確定之日起，至執行完畢滿1年後，方得申請", "自裁判確定之日起，至執行完畢滿2年後，方得申請", "自裁判確定之日起，至執行完畢滿3年後，方得申請"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
