  ('aboriginal-c5fb3965-moex-00290', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '陳男與王女為夫妻，關於夫妻之冠姓，下列敘述何者正確？', '["陳男得申請冠妻姓", "王女得申請冠夫姓，但須待與陳男之婚姻關係消滅後，始得申請回復本姓", "王女得申請冠夫姓，於婚姻關係存續中得申請回復本姓，但應得陳男之同意", "陳男冠妻姓後得申請回復本姓，於同一婚姻關係存續中以2次為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00291', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '關於取用中文姓名之限制，下列敘述何者正確？', '["只要是中文辭典中所列文字均得使用", "無姓氏者，不得僅登記名字", "姓名登記無字數限制", "中文姓名，均得以英文姓名並列登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00292', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '下列何種行為得不使用本名？', '["提起訴願", "出版著作", "請領失業救濟", "報考國家考試"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00293', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '某甲因認為名字字義粗俗不雅申請改名，下列何種情形主管機關應否准其申請？', '["遭檢察官起訴中", "被收養", "第三次改名", "歸化我國國籍後，第二次申請更改中文姓名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
